-- 默认 sql="sql"，表名假设为 "learning_points"，请根据实际情况调整表名
INSERT INTO library (lang, lb_id, difficulty, page, title, tags, summary, content, eg_in, eg_out) VALUES ('python', 31, 'beginner', 1, 'For Loop Introduction', '["循环","for","基础"]', '介绍Python中for循环的基本语法和用法。', 'for循环用于遍历序列（如列表、元组、字符串）或其他可迭代对象。\\n基本语法：for item in iterable:\\n    # 代码块\\n循环体必须缩进。', '["for i in [1, 2, 3]:\\n    print(i)"]', '["1\\n2\\n3"]'), ('python', 32, 'beginner', 1, 'While Loop Basics', '["循环","while","基础"]', '解释while循环的语法和如何基于条件执行循环。', 'while循环在条件为真时重复执行代码块。\\n语法：while condition:\\n    # 代码块\\n注意避免无限循环。', '["count = 0\\nwhile count < 3:\\n    print(count)\\n    count += 1"]', '["0\\n1\\n2"]'), ('python', 33, 'beginner', 1, 'Looping Through Lists', '["循环","列表","遍历"]', '展示如何使用for循环遍历列表中的元素。', '列表是常见的可迭代对象。for循环可以直接遍历列表元素。\\n例如：for element in my_list:\\n    print(element)', '["fruits = [\\"apple\\", \\"banana\\", \\"cherry\\"]\\nfor fruit in fruits:\\n    print(fruit)"]', '["apple\\nbanana\\ncherry"]'), ('python', 34, 'beginner', 1, 'Looping Through Strings', '["循环","字符串","遍历"]', '说明字符串作为字符序列，可以用for循环遍历。', '在Python中，字符串是可迭代的，由字符组成。\\nfor循环可以逐个访问字符串中的字符。', '["for char in \\"hello\\":\\n    print(char)"]', '["h\\ne\\nl\\nl\\no"]'), ('python', 35, 'beginner', 1, 'Using range() in Loops', '["循环","range","函数"]', '介绍range()函数生成数字序列，常用于for循环。', 'range()函数返回一个数字序列，默认从0开始。\\n语法：range(start, stop, step)\\n常用于for i in range(n): 执行n次循环。', '["for i in range(5):\\n    print(i)"]', '["0\\n1\\n2\\n3\\n4"]'), ('python', 36, 'beginner', 1, 'Nested Loops', '["循环","嵌套","多层"]', '解释如何在循环内部使用另一个循环，即嵌套循环。', '嵌套循环是循环内部包含另一个循环。\\n常用于处理多维数据，如二维列表。\\n外层循环每执行一次，内层循环完整执行一遍。', '["for i in range(3):\\n    for j in range(2):\\n        print(i, j)"]', '["0 0\\n0 1\\n1 0\\n1 1\\n2 0\\n2 1"]'), ('python', 37, 'beginner', 1, 'Break Statement in Loops', '["循环","break","控制"]', '介绍break语句用于提前退出循环。', 'break语句用于在满足某个条件时立即终止循环。\\n它通常与if语句结合使用。', '["for i in range(10):\\n    if i == 5:\\n        break\\n    print(i)"]', '["0\\n1\\n2\\n3\\n4"]'), ('python', 38, 'beginner', 1, 'Continue Statement in Loops', '["循环","continue","控制"]', '说明continue语句跳过当前迭代，继续下一次循环。', 'continue语句用于跳过当前循环迭代的剩余部分，直接进入下一次迭代。', '["for i in range(5):\\n    if i == 2:\\n        continue\\n    print(i)"]', '["0\\n1\\n3\\n4"]'), ('python', 39, 'beginner', 1, 'Else Clause with Loops', '["循环","else","子句"]', '解释循环中的else子句在循环正常完成后执行。', '在Python中，循环可以有else子句，当循环没有通过break语句终止时执行。\\n语法：for...else 或 while...else', '["for i in range(3):\\n    print(i)\\nelse:\\n    print(\\"Loop finished\\")"]', '["0\\n1\\n2\\nLoop finished"]'), ('python', 40, 'beginner', 1, 'Infinite Loops and Prevention', '["循环","无限","避免"]', '讨论无限循环的原因和如何避免。', '无限循环是条件始终为真的循环，导致程序无法终止。\\n常见原因：忘记更新循环变量。\\n避免方法：确保循环条件最终变为假。', '["# 错误示例：无限循环\\n# while True:\\n#     print(\\"looping\\")\\n# 应避免或使用break控制\\ncount = 0\\nwhile count < 3:\\n    print(count)\\n    count += 1"]', '["0\\n1\\n2"]'), ('python', 41, 'beginner', 1, 'Loops and List Comprehensions Basics', '["循环","列表推导式","简洁"]', '介绍列表推导式作为循环的简洁替代。', '列表推导式提供了一种简洁的方式来创建列表，基于现有列表或可迭代对象。\\n语法：[expression for item in iterable]', '["# 使用循环\\nsquares = []\\nfor i in range(5):\\n    squares.append(i**2)\\nprint(squares)\\n# 使用列表推导式\\nsquares = [i**2 for i in range(5)]\\nprint(squares)"]', '["[0, 1, 4, 9, 16]\\n[0, 1, 4, 9, 16]"]'), ('python', 42, 'beginner', 1, 'Looping Through Dictionaries', '["循环","字典","遍历"]', '展示如何遍历字典的键、值或键值对。', '字典是可迭代对象，可以遍历其键、值或项（键值对）。\\n使用 keys(), values(), items() 方法。', '["dict = {\\"a\\": 1, \\"b\\": 2, \\"c\\": 3}\\nfor key in dict:\\n    print(key)\\nfor value in dict.values():\\n    print(value)\\nfor key, value in dict.items():\\n    print(key, value)"]', '["a\\nb\\nc\\n1\\n2\\n3\\na 1\\nb 2\\nc 3"]'), ('python', 43, 'beginner', 1, 'Loop Counters', '["循环","计数器","索引"]', '说明如何在循环中使用计数器变量来跟踪迭代次数。', '在循环中，经常需要知道当前迭代的索引。\\n可以使用额外的变量作为计数器，或使用range()结合索引。', '["fruits = [\\"apple\\", \\"banana\\", \\"cherry\\"]\\ncount = 0\\nfor fruit in fruits:\\n    print(count, fruit)\\n    count += 1"]', '["0 apple\\n1 banana\\n2 cherry"]'), ('python', 44, 'beginner', 1, 'Using enumerate() in Loops', '["循环","enumerate","索引"]', '介绍enumerate()函数在循环中同时获取索引和值。', 'enumerate()函数用于在遍历可迭代对象时同时获取索引和值。\\n语法：for index, value in enumerate(iterable):', '["fruits = [\\"apple\\", \\"banana\\", \\"cherry\\"]\\nfor index, fruit in enumerate(fruits):\\n    print(index, fruit)"]', '["0 apple\\n1 banana\\n2 cherry"]'), ('python', 45, 'beginner', 1, 'Conditional Statements in Loops', '["循环","条件","判断"]', '演示如何在循环内部使用if语句进行条件判断。', '在循环体中，可以使用if语句来根据条件执行不同的代码。\\n这允许更灵活的控制流。', '["numbers = [1, 2, 3, 4, 5]\\nfor num in numbers:\\n    if num % 2 == 0:\\n        print(num, \\"is even\\")\\n    else:\\n        print(num, \\"is odd\\")"]', '["1 is odd\\n2 is even\\n3 is odd\\n4 is even\\n5 is odd"]');